(36,1757696970,2,'BE',1,0,32,'tt_content','{\"oldRecord\":{\"pi_flexform\":\"<?xml version=\\\"1.0\\\" encoding=\\\"utf-8\\\" standalone=\\\"yes\\\" ?>\\n<T3FlexForms>\\n    <data>\\n        <sheet index=\\\"sDEF\\\">\\n            <language index=\\\"lDEF\\\">\\n                <field index=\\\"image\\\">\\n                    <value index=\\\"vDEF\\\">1<\\/value>\\n                <\\/field>\\n                <field index=\\\"headline\\\">\\n                    <value index=\\\"vDEF\\\">Start Your Own Business<\\/value>\\n                <\\/field>\\n                <field index=\\\"text\\\">\\n                    <value index=\\\"vDEF\\\">Build your own career and future with T3 Freelancer profile!<\\/value>\\n                <\\/field>\\n            <\\/language>\\n        <\\/sheet>\\n    <\\/data>\\n<\\/T3FlexForms>\"},\"newRecord\":{\"pi_flexform\":\"<?xml version=\\\"1.0\\\" encoding=\\\"utf-8\\\" standalone=\\\"yes\\\" ?>\\n<T3FlexForms>\\n    <data>\\n        <sheet index=\\\"sDEF\\\">\\n            <language index=\\\"lDEF\\\">\\n                <field index=\\\"image\\\">\\n                    <value index=\\\"vDEF\\\">1<\\/value>\\n                <\\/field>\\n                <field index=\\\"headline\\\">\\n                    <value index=\\\"vDEF\\\">Sarah McCarthy<\\/value>\\n                <\\/field>\\n                <field index=\\\"text\\\">\\n                    <value index=\\\"vDEF\\\">I am a web programmer living in M\\u00fcnster, Germany. I create web sites for clients, mainly in TYPO3 but I also work with Wordpress.<\\/value>\\n                <\\/field>\\n            <\\/language>\\n        <\\/sheet>\\n    <\\/data>\\n<\\/T3FlexForms>\"}}',0,'0400$ea396661b348f59044349a631deec044:eeb3ef2adec88a8b5b3e3c510b74be1d'),
