(38,1757697099,2,'BE',1,0,32,'tt_content','{\"oldRecord\":{\"pi_flexform\":\"<?xml version=\\\"1.0\\\" encoding=\\\"utf-8\\\" standalone=\\\"yes\\\" ?>\\n<T3FlexForms>\\n    <data>\\n        <sheet index=\\\"sDEF\\\">\\n            <language index=\\\"lDEF\\\">\\n                <field index=\\\"image\\\">\\n                    <value index=\\\"vDEF\\\">1<\\/value>\\n                <\\/field>\\n                <field index=\\\"headline\\\">\\n                    <value index=\\\"vDEF\\\">Sarah McCarthy<\\/value>\\n                <\\/field>\\n                <field index=\\\"text\\\">\\n                    <value index=\\\"vDEF\\\">I am a web programmer living in M\\u00fcnster, Germany. I create web sites for clients, mainly in TYPO3 but I also work with Wordpress.<\\/value>\\n                <\\/field>\\n            <\\/language>\\n        <\\/sheet>\\n    <\\/data>\\n<\\/T3FlexForms>\"},\"newRecord\":{\"pi_flexform\":\"<?xml version=\\\"1.0\\\" encoding=\\\"utf-8\\\" standalone=\\\"yes\\\" ?>\\n<T3FlexForms>\\n    <data>\\n        <sheet index=\\\"sDEF\\\">\\n            <language index=\\\"lDEF\\\">\\n                <field index=\\\"image\\\">\\n                    <value index=\\\"vDEF\\\">1<\\/value>\\n                <\\/field>\\n                <field index=\\\"headline\\\">\\n                    <value index=\\\"vDEF\\\">Sarah McCarthy<\\/value>\\n                <\\/field>\\n                <field index=\\\"text\\\">\\n                    <value index=\\\"vDEF\\\">I am a web programmer living in M\\u00fcnster, Germany. I create web sites for clients, mainly in TYPO3 but I also work with Wordpress. I have an interest in new technologies, including ai.<\\/value>\\n                <\\/field>\\n            <\\/language>\\n        <\\/sheet>\\n    <\\/data>\\n<\\/T3FlexForms>\"}}',0,'0400$ffed8d3228cdf267330df64a4d0433d0:eeb3ef2adec88a8b5b3e3c510b74be1d'),
(39,1757697138,2,'BE',1,0,32,'tt_content','{\"oldRecord\":{\"pi_flexform\":\"<?xml version=\\\"1.0\\\" encoding=\\\"utf-8\\\" standalone=\\\"yes\\\" ?>\\n<T3FlexForms>\\n    <data>\\n        <sheet index=\\\"sDEF\\\">\\n            <language index=\\\"lDEF\\\">\\n                <field index=\\\"image\\\">\\n                    <value index=\\\"vDEF\\\">1<\\/value>\\n                <\\/field>\\n                <field index=\\\"headline\\\">\\n                    <value index=\\\"vDEF\\\">Sarah McCarthy<\\/value>\\n                <\\/field>\\n                <field index=\\\"text\\\">\\n                    <value index=\\\"vDEF\\\">I am a web programmer living in M\\u00fcnster, Germany. I create web sites for clients, mainly in TYPO3 but I also work with Wordpress. I have an interest in new technologies, including ai.<\\/value>\\n                <\\/field>\\n            <\\/language>\\n        <\\/sheet>\\n    <\\/data>\\n<\\/T3FlexForms>\"},\"newRecord\":{\"pi_flexform\":\"<?xml version=\\\"1.0\\\" encoding=\\\"utf-8\\\" standalone=\\\"yes\\\" ?>\\n<T3FlexForms>\\n    <data>\\n        <sheet index=\\\"sDEF\\\">\\n            <language index=\\\"lDEF\\\">\\n                <field index=\\\"image\\\">\\n                    <value index=\\\"vDEF\\\">1<\\/value>\\n                <\\/field>\\n                <field index=\\\"headline\\\">\\n                    <value index=\\\"vDEF\\\">Sarah McCarthy<\\/value>\\n                <\\/field>\\n                <field index=\\\"text\\\">\\n                    <value index=\\\"vDEF\\\">I am a web programmer living in M\\u00fcnster, Germany. I create web sites for clients, mainly in TYPO3 but I also work with Wordpress. I have an interest in new technologies, including AI.<\\/value>\\n                <\\/field>\\n            <\\/language>\\n        <\\/sheet>\\n    <\\/data>\\n<\\/T3FlexForms>\"}}',0,'0400$3f0dfc4a143861d579723729da2ffad5:eeb3ef2adec88a8b5b3e3c510b74be1d'),
(40,1757698014,2,'BE',1,0,2,'tt_content','{\"oldRecord\":{\"pi_flexform\":\"<?xml version=\\\"1.0\\\" encoding=\\\"utf-8\\\" standalone=\\\"yes\\\" ?>\\n<T3FlexForms>\\n    <data>\\n        <sheet index=\\\"sDEF\\\">\\n            <language index=\\\"lDEF\\\">\\n                <field index=\\\"title\\\">\\n                    <value index=\\\"vDEF\\\">ABOUT<\\/value>\\n                <\\/field>\\n                <field index=\\\"lefttxt\\\">\\n                    <value index=\\\"vDEF\\\">Freelancer is a free bootstrap theme created by Start Bootstrap. The download includes the complete source files including HTML, CSS, and JavaScript as well as optional SASS stylesheets for easy customization.<\\/value>\\n                <\\/field>\\n                <field index=\\\"righttxt\\\">\\n                    <value index=\\\"vDEF\\\">You can create your own custom avatar for the masthead, change the icon in the dividers, and add your email address to the contact form to make it fully functional!<\\/value>\\n                <\\/field>\\n                <field index=\\\"btntxt\\\">\\n                    <value index=\\\"vDEF\\\">Free Download!<\\/value>\\n                <\\/field>\\n                <field index=\\\"btnlink\\\">\\n                    <value index=\\\"vDEF\\\">1<\\/value>\\n                <\\/field>\\n            <\\/language>\\n        <\\/sheet>\\n    <\\/data>\\n<\\/T3FlexForms>\",\"l18n_diffsource\":\"{\\\"pi_flexform\\\":\\\"\\\"}\"},\"newRecord\":{\"pi_flexform\":\"<?xml version=\\\"1.0\\\" encoding=\\\"utf-8\\\" standalone=\\\"yes\\\" ?>\\n<T3FlexForms>\\n    <data>\\n        <sheet index=\\\"sDEF\\\">\\n            <language index=\\\"lDEF\\\">\\n                <field index=\\\"title\\\">\\n                    <value index=\\\"vDEF\\\">ABOUT<\\/value>\\n                <\\/field>\\n                <field index=\\\"lefttxt\\\">\\n                    <value index=\\\"vDEF\\\">Freelancer is a free bootstrap theme created by Start Bootstrap. The download includes the complete source files including HTML, CSS, and JavaScript as well as optional SASS stylesheets for easy customization.<\\/value>\\n                <\\/field>\\n                <field index=\\\"righttxt\\\">\\n                    <value index=\\\"vDEF\\\">You can create your own custom avatar for the masthead, change the icon in the dividers, and add your email address to the contact form to make it fully functional!<\\/value>\\n                <\\/field>\\n                <field index=\\\"btntxt\\\">\\n                    <value index=\\\"vDEF\\\">My CV<\\/value>\\n                <\\/field>\\n                <field index=\\\"btnlink\\\">\\n                    <value index=\\\"vDEF\\\">1<\\/value>\\n                <\\/field>\\n            <\\/language>\\n        <\\/sheet>\\n    <\\/data>\\n<\\/T3FlexForms>\",\"l18n_diffsource\":\"{\\\"CType\\\":\\\"\\\",\\\"colPos\\\":\\\"\\\",\\\"editlock\\\":\\\"\\\",\\\"endtime\\\":\\\"\\\",\\\"fe_group\\\":\\\"\\\",\\\"hidden\\\":\\\"\\\",\\\"pi_flexform\\\":\\\"\\\",\\\"rowDescription\\\":\\\"\\\",\\\"space_after_class\\\":\\\"\\\",\\\"space_before_class\\\":\\\"\\\",\\\"starttime\\\":\\\"\\\"}\"}}',0,'0400$9c3112a11ec40251e4a14aa9e6243dcb:01dbc21fdb1263685b9147b3b1596ea8'),
(41,1757703412,2,'BE',1,0,33,'tt_content','{\"oldRecord\":{\"pi_flexform\":\"<?xml version=\\\"1.0\\\" encoding=\\\"utf-8\\\" standalone=\\\"yes\\\" ?>\\n<T3FlexForms>\\n    <data>\\n        <sheet index=\\\"sDEF\\\">\\n            <language index=\\\"lDEF\\\">\\n                <field index=\\\"title\\\">\\n                    <value index=\\\"vDEF\\\">PROJECTS<\\/value>\\n                <\\/field>\\n                <field index=\\\"portfolio\\\">\\n                    <el index=\\\"el\\\">\\n                        <field index=\\\"61bb49681bb88771005091\\\">\\n                            <value index=\\\"container\\\">\\n                                <el>\\n                                    <field index=\\\"image\\\">\\n                                        <value index=\\\"vDEF\\\">t3:\\/\\/file?uid=27<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"description\\\">\\n                                        <value index=\\\"vDEF\\\">I have 6 years TYPO3 experience working in a small TYPO3 agency as an integrator\\/developer.<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"headline\\\">\\n                                        <value index=\\\"vDEF\\\">TYPO3<\\/value>\\n                                    <\\/field>\\n                                <\\/el>\\n                            <\\/value>\\n                            <value index=\\\"_TOGGLE\\\">1<\\/value>\\n                        <\\/field>\\n                        <field index=\\\"61bb4a540ec52352802764\\\">\\n                            <value index=\\\"container\\\">\\n                                <el>\\n                                    <field index=\\\"image\\\">\\n                                        <value index=\\\"vDEF\\\">t3:\\/\\/file?uid=32<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"description\\\">\\n                                        <value index=\\\"vDEF\\\">I worked as a software developer\\/ 3rd line support in London between 1996 and 2009. I worked for a bank, a large American consultancy, document management system companies and local government. <\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"headline\\\">\\n                                        <value index=\\\"vDEF\\\">Programmer<\\/value>\\n                                    <\\/field>\\n                                <\\/el>\\n                            <\\/value>\\n                            <value index=\\\"_TOGGLE\\\">1<\\/value>\\n                        <\\/field>\\n                        <field index=\\\"61bb4a59df85e090340053\\\">\\n                            <value index=\\\"container\\\">\\n                                <el>\\n                                    <field index=\\\"image\\\">\\n                                        <value index=\\\"vDEF\\\">t3:\\/\\/file?uid=33<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"description\\\">\\n                                        <value index=\\\"vDEF\\\">I was on the winning team in the M\\u00fcnster Hackathon 2024. We used the open data api to produce weekly podcasts summarizing local government decisions in a bitesize format.<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"headline\\\">\\n                                        <value index=\\\"vDEF\\\">Hackathon<\\/value>\\n                                    <\\/field>\\n                                <\\/el>\\n                            <\\/value>\\n                            <value index=\\\"_TOGGLE\\\">1<\\/value>\\n                        <\\/field>\\n                        <field index=\\\"61bb4a632e9f3046467276\\\">\\n                            <value index=\\\"container\\\">\\n                                <el>\\n                                    <field index=\\\"image\\\">\\n                                        <value index=\\\"vDEF\\\">t3:\\/\\/file?uid=31<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"description\\\">\\n                                        <value index=\\\"vDEF\\\">I recently completed a short course as a Digital Shaper with Techlabs M\\u00fcnster. My team used python to analyse statistics on weather and bicycle use patterns in M\\u00fcnster.<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"headline\\\">\\n                                        <value index=\\\"vDEF\\\">Data science<\\/value>\\n                                    <\\/field>\\n                                <\\/el>\\n                            <\\/value>\\n                            <value index=\\\"_TOGGLE\\\">1<\\/value>\\n                        <\\/field>\\n                    <\\/el>\\n                <\\/field>\\n                <field index=\\\"image\\\">\\n                    <value index=\\\"vDEF\\\">12<\\/value>\\n                <\\/field>\\n                <field index=\\\"description\\\">\\n                    <value index=\\\"vDEF\\\">Showcase your baking skills to the whole world through well-documented recipes, baking videos or presentations, and firmly established connections. If you are a master baker and have a knack for advertising your skills to the world, you will create out of yourself a fine freelance baker.<\\/value>\\n                <\\/field>\\n            <\\/language>\\n        <\\/sheet>\\n    <\\/data>\\n<\\/T3FlexForms>\"},\"newRecord\":{\"pi_flexform\":\"<?xml version=\\\"1.0\\\" encoding=\\\"utf-8\\\" standalone=\\\"yes\\\" ?>\\n<T3FlexForms>\\n    <data>\\n        <sheet index=\\\"sDEF\\\">\\n            <language index=\\\"lDEF\\\">\\n                <field index=\\\"title\\\">\\n                    <value index=\\\"vDEF\\\">PROJECTS<\\/value>\\n                <\\/field>\\n                <field index=\\\"portfolio\\\">\\n                    <el index=\\\"el\\\">\\n                        <field index=\\\"61bb49681bb88771005091\\\">\\n                            <value index=\\\"container\\\">\\n                                <el>\\n                                    <field index=\\\"image\\\">\\n                                        <value index=\\\"vDEF\\\">t3:\\/\\/file?uid=27<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"description\\\">\\n                                        <value index=\\\"vDEF\\\">I have 7 years TYPO3 experience working in a small TYPO3 agency as an integrator\\/developer. I am the co-team lead of the TYPO3 Documentation Team and contribute regularly to the official documentation. I am a member of the Education Team and help create official certification questions.<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"headline\\\">\\n                                        <value index=\\\"vDEF\\\">TYPO3<\\/value>\\n                                    <\\/field>\\n                                <\\/el>\\n                            <\\/value>\\n                            <value index=\\\"_TOGGLE\\\">1<\\/value>\\n                        <\\/field>\\n                        <field index=\\\"61bb4a540ec52352802764\\\">\\n                            <value index=\\\"container\\\">\\n                                <el>\\n                                    <field index=\\\"image\\\">\\n                                        <value index=\\\"vDEF\\\">t3:\\/\\/file?uid=32<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"description\\\">\\n                                        <value index=\\\"vDEF\\\">I worked as a software developer\\/ 3rd line support in London between 1996 and 2009. I worked for a bank, a large American consultancy, document management system companies and local government. <\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"headline\\\">\\n                                        <value index=\\\"vDEF\\\">Programmer<\\/value>\\n                                    <\\/field>\\n                                <\\/el>\\n                            <\\/value>\\n                            <value index=\\\"_TOGGLE\\\">1<\\/value>\\n                        <\\/field>\\n                        <field index=\\\"61bb4a59df85e090340053\\\">\\n                            <value index=\\\"container\\\">\\n                                <el>\\n                                    <field index=\\\"image\\\">\\n                                        <value index=\\\"vDEF\\\">t3:\\/\\/file?uid=33<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"description\\\">\\n                                        <value index=\\\"vDEF\\\">I was on the winning team in the M\\u00fcnster Hackathon 2024. We used the M\\u00fcnster Open Data API (Oparl Open Data interface) to produce weekly podcasts summarizing local government decisions in a a bitesize format.<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"headline\\\">\\n                                        <value index=\\\"vDEF\\\">Hackathon<\\/value>\\n                                    <\\/field>\\n                                <\\/el>\\n                            <\\/value>\\n                            <value index=\\\"_TOGGLE\\\">1<\\/value>\\n                        <\\/field>\\n                        <field index=\\\"61bb4a632e9f3046467276\\\">\\n                            <value index=\\\"container\\\">\\n                                <el>\\n                                    <field index=\\\"image\\\">\\n                                        <value index=\\\"vDEF\\\">t3:\\/\\/file?uid=31<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"description\\\">\\n                                        <value index=\\\"vDEF\\\">I recently completed a short course as a Digital Shaper with Techlabs M\\u00fcnster. My team used python to analyse statistics on weather and bicycle use patterns in M\\u00fcnster.<\\/value>\\n                                    <\\/field>\\n                                    <field index=\\\"headline\\\">\\n                                        <value index=\\\"vDEF\\\">Data science<\\/value>\\n                                    <\\/field>\\n                                <\\/el>\\n                            <\\/value>\\n                            <value index=\\\"_TOGGLE\\\">1<\\/value>\\n                        <\\/field>\\n                    <\\/el>\\n                <\\/field>\\n                <field index=\\\"image\\\">\\n                    <value index=\\\"vDEF\\\">12<\\/value>\\n                <\\/field>\\n                <field index=\\\"description\\\">\\n                    <value index=\\\"vDEF\\\">Showcase your baking skills to the whole world through well-documented recipes, baking videos or presentations, and firmly established connections. If you are a master baker and have a knack for advertising your skills to the world, you will create out of yourself a fine freelance baker.<\\/value>\\n                <\\/field>\\n            <\\/language>\\n        <\\/sheet>\\n    <\\/data>\\n<\\/T3FlexForms>\"}}',0,'0400$1e1a697a762aaf43f68898a4c3ad2931:c1c3d2254ecfaef40b15a18e94a89b96'),
(42,1757703571,2,'BE',1,0,2,'tt_content','{\"oldRecord\":{\"pi_flexform\":\"<?xml version=\\\"1.0\\\" encoding=\\\"utf-8\\\" standalone=\\\"yes\\\" ?>\\n<T3FlexForms>\\n    <data>\\n        <sheet index=\\\"sDEF\\\">\\n            <language index=\\\"lDEF\\\">\\n                <field index=\\\"title\\\">\\n                    <value index=\\\"vDEF\\\">ABOUT<\\/value>\\n                <\\/field>\\n                <field index=\\\"lefttxt\\\">\\n                    <value index=\\\"vDEF\\\">Freelancer is a free bootstrap theme created by Start Bootstrap. The download includes the complete source files including HTML, CSS, and JavaScript as well as optional SASS stylesheets for easy customization.<\\/value>\\n                <\\/field>\\n                <field index=\\\"righttxt\\\">\\n                    <value index=\\\"vDEF\\\">You can create your own custom avatar for the masthead, change the icon in the dividers, and add your email address to the contact form to make it fully functional!<\\/value>\\n                <\\/field>\\n                <field index=\\\"btntxt\\\">\\n                    <value index=\\\"vDEF\\\">My CV<\\/value>\\n                <\\/field>\\n                <field index=\\\"btnlink\\\">\\n                    <value index=\\\"vDEF\\\">1<\\/value>\\n                <\\/field>\\n            <\\/language>\\n        <\\/sheet>\\n    <\\/data>\\n<\\/T3FlexForms>\"},\"newRecord\":{\"pi_flexform\":\"<?xml version=\\\"1.0\\\" encoding=\\\"utf-8\\\" standalone=\\\"yes\\\" ?>\\n<T3FlexForms>\\n    <data>\\n        <sheet index=\\\"sDEF\\\">\\n            <language index=\\\"lDEF\\\">\\n                <field index=\\\"title\\\">\\n                    <value index=\\\"vDEF\\\">ABOUT<\\/value>\\n                <\\/field>\\n                <field index=\\\"lefttxt\\\">\\n                    <value index=\\\"vDEF\\\">I have lived in M\\u00fcnster since 2009.I am an English native speaker<\\/value>\\n                <\\/field>\\n                <field i